# 大文件备份脚本
# 将超过100MB的大文件备份到指定位置

param(
    [string]$SourcePath = "C:\Users\WH\.openclaw\workspace",
    [string]$BackupPath = "C:\Users\WH\Desktop\AI神谕\openclaw任务成果\大文件备份"
)

# 创建备份目录
if (-not (Test-Path $BackupPath)) {
    New-Item -ItemType Directory -Path $BackupPath -Force
}

# 查找所有超过100MB的文件
$largeFiles = Get-ChildItem -Path $SourcePath -Recurse -File | 
    Where-Object { $_.Length -gt 100MB } |
    Select-Object FullName, @{Name="SizeMB";Expression={[math]::Round($_.Length/1MB,2)}}

if ($largeFiles.Count -eq 0) {
    Write-Host "没有找到超过100MB的大文件。" -ForegroundColor Green
    exit 0
}

Write-Host "找到 $($largeFiles.Count) 个大文件：" -ForegroundColor Yellow
$largeFiles | Format-Table -AutoSize

# 备份大文件
foreach ($file in $largeFiles) {
    $relativePath = $file.FullName.Substring($SourcePath.Length).TrimStart('\')
    $backupFile = Join-Path $BackupPath $relativePath

    # 创建目标目录
    $backupDir = Split-Path $backupFile -Parent
    if (-not (Test-Path $backupDir)) {
        New-Item -ItemType Directory -Path $backupDir -Force
    }

    # 复制文件
    Copy-Item -Path $file.FullName -Destination $backupFile -Force
    Write-Host "已备份: $relativePath ($($file.SizeMB) MB)" -ForegroundColor Cyan
}

Write-Host "`n大文件备份完成！备份位置: $BackupPath" -ForegroundColor Green

# 生成备份清单
$manifestPath = Join-Path $BackupPath "backup-manifest-$(Get-Date -Format 'yyyyMMdd-HHmmss').txt"
$largeFiles | ForEach-Object {
    "$($_.FullName)|$($_.SizeMB) MB"
} | Set-Content -Path $manifestPath

Write-Host "备份清单: $manifestPath" -ForegroundColor Yellow

# 智能Git推送脚本
# 自动检测并处理大文件问题

param(
    [string]$Remote = "backup",
    [string]$Branch = "master"
)

$WorkspacePath = "C:\Users\WH\.openclaw\workspace"
Set-Location $WorkspacePath

Write-Host "=== 智能Git推送 ===" -ForegroundColor Cyan
Write-Host "远程仓库: $Remote"
Write-Host "分支: $Branch"
Write-Host ""

# 1. 检查大文件
Write-Host "1. 检查大文件..." -ForegroundColor Yellow
$largeFiles = git ls-files | ForEach-Object {
    $file = Join-Path $WorkspacePath $_
    if (Test-Path $file -PathType Leaf) {
        $size = (Get-Item $file).Length
        if ($size -gt 100MB) {
            [PSCustomObject]@{
                File = $_
                SizeMB = [math]::Round($size/1MB, 2)
            }
        }
    }
}

if ($largeFiles) {
    Write-Host "发现 $($largeFiles.Count) 个大文件：" -ForegroundColor Red
    $largeFiles | Format-Table -AutoSize

    # 询问如何处理
    Write-Host "`n如何处理大文件？" -ForegroundColor Yellow
    Write-Host "1. 使用Git LFS（推荐）"
    Write-Host "2. 排除这些文件（添加到.gitignore）"
    Write-Host "3. 先备份再排除"
    Write-Host "4. 取消推送"

    $choice = Read-Host "请选择 (1-4)"

    switch ($choice) {
        "1" {
            # 使用Git LFS
            Write-Host "启用Git LFS..." -ForegroundColor Green
            git lfs install
            foreach ($file in $largeFiles) {
                git lfs track $file.File
            }
            git add .gitattributes
        }
        "2" {
            # 添加到.gitignore
            Write-Host "添加到.gitignore..." -ForegroundColor Green
            foreach ($file in $largeFiles) {
                Add-Content -Path ".gitignore" -Value "`n$($file.File)"
            }
            git add .gitignore
        }
        "3" {
            # 先备份
            Write-Host "备份大文件..." -ForegroundColor Green
            & "$PSScriptRoot\backup-large-files.ps1"

            # 然后从Git中移除
            foreach ($file in $largeFiles) {
                git rm --cached $file.File
                Add-Content -Path ".gitignore" -Value "`n$($file.File)"
            }
            git add .gitignore
        }
        "4" {
            Write-Host "推送已取消。" -ForegroundColor Yellow
            exit 0
        }
    }
}

# 2. 提交更改
Write-Host "`n2. 提交更改..." -ForegroundColor Yellow
$commitMessage = Read-Host "输入提交信息（留空使用默认）"
if ([string]::IsNullOrWhiteSpace($commitMessage)) {
    $commitMessage = "Auto commit: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
}

git add .
git commit -m $commitMessage

# 3. 推送
Write-Host "`n3. 推送到 $Remote/$Branch..." -ForegroundColor Yellow
try {
    git push $Remote $Branch
    Write-Host "推送成功！" -ForegroundColor Green
} catch {
    Write-Host "推送失败: $_" -ForegroundColor Red

    # 尝试强制推送
    $force = Read-Host "是否尝试强制推送？ (y/n)"
    if ($force -eq "y") {
        git push $Remote $Branch --force
        Write-Host "强制推送完成。" -ForegroundColor Green
    }
}

Write-Host "`n=== 完成 ===" -ForegroundColor Cyan

